<?php
namespace App\Models;use App\Models\Concerns\BelongsToWorkspace;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class DailyReport extends Model{use BelongsToWorkspace,SoftDeletes;public const STATUSES=['draft','submitted','reviewed','approved','rejected'];protected $fillable=['workspace_id','user_id','report_date','status','completed_summary','in_progress_summary','pending_summary','blocker_summary','tomorrow_plan','submitted_at','reviewed_by','reviewed_at','review_comment','quality_score','is_late'];protected function casts():array{return['report_date'=>'date','submitted_at'=>'datetime','reviewed_at'=>'datetime','is_late'=>'boolean'];}public function user(){return $this->belongsTo(User::class);}public function reviewer(){return $this->belongsTo(User::class,'reviewed_by');}public function items(){return $this->hasMany(DailyReportItem::class)->orderBy('sort_order');}public function proofs(){return $this->hasMany(WorkProof::class);}}
